// Certificate Management via SCEP
package scep

import (
	"context"
	"time"

	"github.com/arminguenther/xeruspower-go/cert/serversslcert"
	"github.com/arminguenther/xeruspower-go/idl"
	"github.com/arminguenther/xeruspower-go/idl/event"
)

const (
	NO_ERROR           int32 = 0
	ERR_INVALID_PARAMS int32 = 1
)

// SCEP interface
type Scep interface {
	idl.Object

	// Enable SCEP. This will reset a previous SCEP setup and start with the initial enrollment again.
	//
	//	@param initialEnrollmentData
	//	@param scepSettings
	//
	//	@return NO_ERROR              enabled SCEP successfully
	//	@return ERR_INVALID_PARAMS    one of the parameters was invalid
	EnableScep(ctx context.Context, initialEnrollmentData EnrollmentData, scepSettings Settings) (int32, error)

	// Disable SCEP and discard all settings of this SCEP setup, allowing
	// manual management of the TLS certificate again.
	// Re-enabling SCEP will start with the initial enrollment again.
	DiscardScep(ctx context.Context) error

	// Get the data that is used for the initial enrollment. For Renewals,
	// this is not used anymore.
	//
	//	@return initial enrollment data
	GetInitialEnrollmentData(ctx context.Context) (EnrollmentData, error)

	// Get the SCEP settings.
	//
	//	@return SCEP settings
	GetSettings(ctx context.Context) (Settings, error)

	// Get the SCEP status.
	//
	//	@return SCEP status
	GetStatus(ctx context.Context) (Status, error)

	// Set SCEP settings of an existing SCEP setup. Note, that this will
	// kill a currently running SCEP enrollment and immediately retry.
	//
	//	@return NO_ERROR              changed ScepSettings successfully
	//	@return ERR_INVALID_PARAMS    one of the parameters was invalid
	SetSettings(ctx context.Context, scepSettings Settings) (int32, error)

	// Get all supported key variants.
	//
	//	@return Vector of KeyInfo structures representing all supported key variants
	GetSupportedKeyInfos(ctx context.Context) ([]serversslcert.KeyInfo, error)
}

// Data needed for initial enrollment
type EnrollmentData struct {
	Challenge string                // The SCEP challenge password. Write-only.
	CertInfo  serversslcert.ReqInfo // Data of the Certificate Signing Request that will be created
}

// Settings for all SCEP enrollments (initial and renewal)
type Settings struct {
	CaCertFingerprint      string // The fingerprint of the trusted CA certificate
	Url                    string // SCEP server url
	RenewDaysBeforeExpiry  int32  // Run renewal if the certificate will expire in <n> days
	PendingWaitTimeSeconds int32  // In pending state, seconds between polling messages
	PendingRetries         int32  // In pending state, how many polling messages will be sent before exiting with failure
	// Do not verify whether the issued end-entity certificate
	// builds a chain of trust up to the SCEP Root CA cert
	SkipVerificationOfIssuedCertChain bool
}

type EnrollmentRunStatus int

const (
	NOT_RUN EnrollmentRunStatus = iota // Enrollment has not run yet
	STARTED                            // Enrollment run started
	PENDING                            // Enrollment run went to pending state
	SUCCESS                            // Enrollment run succeeded
	FAILED                             // Enrollment run failed
)

type EnrollmentRunInfo struct {
	Status        EnrollmentRunStatus // Status of the enrollment run. If NOT_RUN, the other values can be ignored.
	StartedAt     time.Time           // Unix timestamp (UTC) of when the enrollment started
	EndedAt       time.Time           // Unix timestamp (UTC) of when the enrollment ended or 0 if still running
	FailureReason string              // In case of status FAILED, a textual description of the error
}

// The current status of SCEP
type Status struct {
	Enabled bool // Is SCEP enabled
	// Unix timestamp (UTC) of the last successful enrollment, or 0 if that has
	// not happened with the current SCEP setup (will be reset to 0 with a call
	// to enableScep
	LastSuccessfulEnrollment time.Time
	LastEnrollmentRunInfo    EnrollmentRunInfo // Info about the last (possibly still ongoing) enrollment run
}

type StatusChangedEvent interface {
	event.Event
	NewStatus() Status
	isStatusChangedEvent()
}
